DROP TABLE IF EXISTS "event";
CREATE TABLE "event" (
  "id" integer NOT NULL PRIMARY KEY AUTOINCREMENT,
  "title" varchar NOT NULL,
  "description" text NOT NULL,
  "date" datetime NOT NULL,
  "startTime" varchar,
  "endTime" varchar,
  "location" varchar NOT NULL,
  "capacity" integer NOT NULL,
