  "updatedAt" datetime NOT NULL DEFAULT (datetime('now')),
  "address" text,
  "registeredCount" integer NOT NULL DEFAULT (0),
  "tags" varchar,
  "viewCount" integer NOT NULL DEFAULT (0),
  "likeCount" integer NOT NULL DEFAULT (0),
  "favoriteCount" integer NOT NULL DEFAULT (0),
  "commentCount" integer NOT NULL DEFAULT (0),
  "isSponsored" boolean NOT NULL DEFAULT (0),
  "categoryId" integer,
  CONSTRAINT "FK_19642e6a244b4885e14eab0fdc0" FOREIGN KEY ("organizerId") REFERENCES "user" ("id") ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT "FK_d44e52c4ca04619ef9b61a11982" FOREIGN KEY ("categoryId") REFERENCES "category" ("id") ON DELETE NO ACTION ON UPDATE NO ACTION
);

