  "amount" float NOT NULL,
  "paymentMethod" varchar,
  "transactionId" varchar,
  "status" varchar NOT NULL DEFAULT ('pending'),
  "createdAt" datetime NOT NULL DEFAULT (datetime('now')),
  "updatedAt" datetime NOT NULL DEFAULT (datetime('now')),
  "eventId" integer NOT NULL,
  CONSTRAINT "FK_f99298ea8a12021db8dd35c4f29" FOREIGN KEY ("registrationId") REFERENCES "registration" ("id") ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT "FK_b046318e0b341a7f72110b75857" FOREIGN KEY ("userId") REFERENCES "user" ("id") ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT "FK_7acc01aea1ff8f19abf62781770" FOREIGN KEY ("eventId") REFERENCES "event" ("id") ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT "REL_f99298ea8a12021db8dd35c4f2" UNIQUE ("registrationId" ASC)
);

