  "updatedAt" datetime NOT NULL DEFAULT (datetime('now')),
  CONSTRAINT "FK_7d59d59c095d1b275b825c8861c" FOREIGN KEY ("eventId") REFERENCES "event" ("id") ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT "FK_5e444a1a1698d467de0298b2430" FOREIGN KEY ("organizerId") REFERENCES "user" ("id") ON DELETE NO ACTION ON UPDATE NO ACTION
);

