DROP TABLE IF EXISTS "wallet";
CREATE TABLE "wallet" (
  "id" integer NOT NULL PRIMARY KEY AUTOINCREMENT,
  "userId" integer NOT NULL,
  "balance" decimal(10,2) NOT NULL DEFAULT (0),
  "status" varchar NOT NULL DEFAULT ('active'),
  "createdAt" datetime NOT NULL DEFAULT (datetime('now')),
  "updatedAt" datetime NOT NULL DEFAULT (datetime('now')),
  CONSTRAINT "FK_35472b1fe48b6330cd349709564" FOREIGN KEY ("userId") REFERENCES "user" ("id") ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT "UQ_35472b1fe48b6330cd349709564" UNIQUE ("userId" ASC),
  CONSTRAINT "REL_35472b1fe48b6330cd34970956" UNIQUE ("userId" ASC)
);

