DROP TABLE IF EXISTS "wallet_transaction";
CREATE TABLE "wallet_transaction" (
  "id" integer NOT NULL PRIMARY KEY AUTOINCREMENT,
  "walletId" integer NOT NULL,
  "userId" integer NOT NULL,
  "amount" decimal(10,2) NOT NULL,
  "type" varchar NOT NULL,
  "description" varchar,
  "status" varchar NOT NULL DEFAULT ('completed'),
  "orderId" varchar,
  "relatedId" integer,
  "createdAt" datetime NOT NULL DEFAULT (datetime('now')),
  CONSTRAINT "FK_07de5136ba8e92bb97d45b9a7af" FOREIGN KEY ("walletId") REFERENCES "wallet" ("id") ON DELETE NO ACTION ON UPDATE NO ACTION,
  CONSTRAINT "FK_9071d3c9266c4521bdafe29307a" FOREIGN KEY ("userId") REFERENCES "user" ("id") ON DELETE NO ACTION ON UPDATE NO ACTION
);

